requirements.capl_script:
/* GW-REQ-01 */
variables
{
  msTimer speedTxTimer;
  float lastVehicleSpeed = 0.0;
}

on start
{
  write("GW Simulation started for GW-REQ-01");
  setTimer(speedTxTimer, 100);
}

on message ECM_VehicleData
{
  lastVehicleSpeed = this.VehicleSpeed;
  write("GW received VehicleSpeed from ECM: %.1f km/h", lastVehicleSpeed);
}

on timer speedTxTimer
{
  message GW_VehicleStatus msg;
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msg.byte(i) = 0;
  }
  msg.dlc = 8;
  msg.GW_SpeedOut = lastVehicleSpeed;
  output(msg);
  write("GW transmitted GW_SpeedOut to IC: %.1f km/h", lastVehicleSpeed);
  setTimer(speedTxTimer, 100);
}

/* GW-REQ-02 */
variables
{
  message ECM_VehicleData ecmMsg;
  message GW_VehicleStatus gwMsg;
  float physicalSpeed;
  float boundedSpeed;
}

on message ECM_VehicleData
{
  physicalSpeed = this.VehicleSpeed;
  if (physicalSpeed < 0)
    boundedSpeed = 0;
  else if (physicalSpeed > 250)
    boundedSpeed = 250;
  else
    boundedSpeed = physicalSpeed;

  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwMsg.byte(i) = 0;
  }
  gwMsg.dlc = 8;
  gwMsg.GW_SpeedOut = boundedSpeed;
  output(gwMsg);
}

/* GW-REQ-03 */
variables
{
  message GW_VehicleStatus gwStatusMsg;
  message GW_Warnings gwWarnMsg;
}

on message BCM_BodyStatus
{
  int anyDoor = (this.DriverDoorOpen || this.PassengerDoorOpen);
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwStatusMsg.byte(i) = 0;
  }
  gwStatusMsg.dlc = 8;
  gwStatusMsg.AnyDoorOpen = anyDoor;
  // Reset payload before setting signals
  for (i = 0; i < 8; i++)
  {
    gwWarnMsg.byte(i) = 0;
  }
  gwWarnMsg.dlc = 8;
  gwWarnMsg.DoorWarning = anyDoor;
  output(gwStatusMsg);
  output(gwWarnMsg);
}

