/* GW-REQ-09 */
variables
{
  const float OVERSPEED_THRESHOLD = 120.0;
}

on message ECM_VehicleData
{
  message GW_Warnings warningMsg;
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    warningMsg.byte(i) = 0;
  }
  warningMsg.dlc = 8;
  warningMsg.OverspeedWarning = (this.VehicleSpeed > OVERSPEED_THRESHOLD);
  output(warningMsg);
}

/* GW-REQ-10 */
variables
{
  int previousOverspeedStatus = 0;
  const float OVERSPEED_THRESHOLD = 120.0;
}

on message ECM_VehicleData
{
  int overspeedStatus = (this.VehicleSpeed > OVERSPEED_THRESHOLD);
  if (overspeedStatus != previousOverspeedStatus)
  {
    message GW_Warnings msgWarnings;
    // Reset payload before setting signals
    int i;
    for (i = 0; i < 8; i++)
    {
      msgWarnings.byte(i) = 0;
    }
    msgWarnings.dlc = 8;
    msgWarnings.OverspeedWarning = overspeedStatus;
    output(msgWarnings);
  }
  previousOverspeedStatus = overspeedStatus;
}

/* GW-REQ-11 */
variables
{
  float vehicleSpeed = 0;
}

on message ECM_VehicleData
{
  vehicleSpeed = this.VehicleSpeed;
}

on message BCM_BodyStatus
{
  message GW_Warnings msgGW;
  int anyDoor = (this.DriverDoorOpen || this.PassengerDoorOpen);
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  msgGW.DoorWarning = (vehicleSpeed > 0 && anyDoor);
  output(msgGW);
}

/* GW-REQ-12 */
variables
{
  int prevDriverDoor = -1;
  int prevPassengerDoor = -1;
}

on message BCM_BodyStatus
{
  int driverDoor = this.DriverDoorOpen;
  int passengerDoor = this.PassengerDoorOpen;

  if (driverDoor != prevDriverDoor || passengerDoor != prevPassengerDoor)
  {
    message GW_Warnings msgWarnings;
    // Reset payload before setting signals
    int i;
    for (i = 0; i < 8; i++)
    {
      msgWarnings.byte(i) = 0;
    }
    msgWarnings.dlc = 8;
    msgWarnings.DoorWarning = (driverDoor || passengerDoor);
    output(msgWarnings);
  }

  prevDriverDoor = driverDoor;
  prevPassengerDoor = passengerDoor;
}
